const allData = {{workflowparams:allData}};
const zeroQtyArray = [];
for (const [index, gr] of allData.table_gr.entries()) {
  if (gr.received_qty <= 0) zeroQtyArray.push(`#${index + 1}`);
}
let hasZero = 0;
let message = null;
if (zeroQtyArray.length > 0) {
  message = `Line${zeroQtyArray.length > 1 ? "s" : ""} ${zeroQtyArray.join(", ")} ha${zeroQtyArray.length > 1 ? "ve" : "s"} a zero received quantity.\nIf you proceed, those rows will be removed.\nWould you like to proceed?`;
  hasZero = 1;
}
return { message, hasZero };

let allData = {{workflowparams:allData}};
const pageStatus = {{workflowparams:pageStatus}};
const updatedGR = [];

for (const [index, grLineItem] of allData.table_gr.entries()) {
  grLineItem.supplier_id = allData.supplier_name || null;
  grLineItem.organization_id = allData.organization_id;
  grLineItem.plant_id = allData.plant_id || null;
  grLineItem.billing_state_id = allData.billing_address_state || null;
  grLineItem.billing_country_id = allData.billing_address_country || null;
  grLineItem.shipping_state_id = allData.shipping_address_state || null;
  grLineItem.shipping_country_id = allData.shipping_address_country || null;
  grLineItem.assigned_to = allData.assigned_to || null;
  grLineItem.line_index = index + 1;
  updatedGR.push(grLineItem);
}
allData.table_gr = updatedGR;

allData.gr_status = "Created";

if (allData.gr_no_type !== -9999 &&
    (!allData.gr_no || allData.gr_no === null || allData.gr_no === "" || allData.previous_status === "Draft")) {
  allData.gr_no = "issued";
}

allData.table_gr = allData.table_gr.filter((item) => item.received_qty > 0);

let poID = [];
let purchaseOrderNumber = [];
for (const gr of allData.table_gr) {
  poID.push(gr.line_po_id);
  purchaseOrderNumber.push(gr.line_po_no);
}
poID = [...new Set(poID)];
purchaseOrderNumber = [...new Set(purchaseOrderNumber)];
allData.po_id = poID;
allData.po_no_display = purchaseOrderNumber.join(", ");

let invalidMessage;
if (allData.table_gr.length === 0) {
  invalidMessage = "All Received Quantity must not be 0. Please add at least one item with received quantity > 0.";
}

const poIds = Array.isArray(allData.po_id) ? allData.po_id : [allData.po_id];
const searchGrId = (pageStatus === "Edit" && allData.id) ? allData.id : null;

return { allData, poIds, invalidMessage, searchGrId };

const allData = {{node:cn_fill.data.allData}};
const tableGR = allData.table_gr || [];
const errors = [];

const headerRequired = [
  { name: "gr_no", label: "Good Receiving Number" },
  { name: "gr_date", label: "Received Date" },
  { name: "plant_id", label: "Plant" },
];
for (const f of headerRequired) {
  const v = allData[f.name];
  if (v === undefined || v === null || (typeof v === "string" && v.trim() === "")) {
    errors.push(f.label + " is required.");
  }
}
if (tableGR.length === 0) errors.push("GR Items are required.");

for (let i = 0; i < tableGR.length; i++) {
  const item = tableGR[i];
  const isSplitParent = item.is_split === "Yes" && item.parent_or_child === "Parent";
  if (isSplitParent) continue;

  if (!item.location_id) errors.push(`Target Location is required for item #${i + 1}.`);
  if (!item.inv_category) errors.push(`Inventory Category is required for item #${i + 1}.`);
  if (!item.item_batch_no) errors.push(`Batch Number is required for item #${i + 1}.`);

  if (item.is_serialized_item === 1 && item.is_serial_allocated !== 1) {
    const id = item.item_name || item.item_code || item.item_id || `Item #${i + 1}`;
    errors.push(`Serial number allocation is required for ${id} (row ${i + 1}).`);
  }
}

const hasError = errors.length > 0 ? 1 : 0;
const errorMessage = hasError ? errors.join("\n") : null;
return { hasError, errorMessage };

const tableData = {{node:cn_fill.data.allData.table_gr}} || [];
const itemIdsSet = new Set();
for (const grItem of tableData) {
  if (grItem.item_id) itemIdsSet.add(grItem.item_id);
}
return { itemIds: Array.from(itemIdsSet) };

const roundQty = (v) => parseFloat(parseFloat(v || 0).toFixed(3));

const tableGR = {{node:cn_fill.data.allData.table_gr}} || [];
const poDataList = {{node:search_po.data.data}} || [];
const itemDataList = {{node:search_items.data.data}} || [];
const pageStatus = {{workflowparams:pageStatus}};
const origRaw = {{node:search_origGR.data.data}} || [];
const originalGR = Array.isArray(origRaw) ? (origRaw[0] || null) : origRaw;
const originalTableGR = (originalGR && originalGR.table_gr) ? originalGR.table_gr : [];

const poLineMap = new Map();
for (const po of poDataList) {
  for (const line of (po.table_po || [])) poLineMap.set(line.id, line);
}
const tolMap = new Map();
for (const it of itemDataList) tolMap.set(it.id, parseFloat(it.over_receive_tolerance || 0));

const isParent = (r) => r.is_split === "Yes" && r.parent_or_child === "Parent";

const newAgg = new Map();
const itemByLine = new Map();
const nameByLine = new Map();
for (const gr of tableGR) {
  if (isParent(gr)) continue;
  const lid = gr.po_line_item_id;
  if (!lid) continue;
  newAgg.set(lid, roundQty((newAgg.get(lid) || 0) + parseFloat(gr.received_qty || 0)));
  if (!itemByLine.has(lid)) itemByLine.set(lid, gr.item_id);
  if (!nameByLine.has(lid)) nameByLine.set(lid, gr.item_name || gr.item_id || lid);
}
const oldAgg = new Map();
for (const gr of originalTableGR) {
  if (isParent(gr)) continue;
  const lid = gr.po_line_item_id;
  if (!lid) continue;
  oldAgg.set(lid, roundQty((oldAgg.get(lid) || 0) + parseFloat(gr.received_qty || 0)));
}

const hardErrors = [];
const warnings = [];
for (const [lid, newQty] of newAgg) {
  const poLine = poLineMap.get(lid);
  if (!poLine) continue;
  const tol = tolMap.get(itemByLine.get(lid)) || 0;
  const name = nameByLine.get(lid);
  const ordered = parseFloat(poLine.quantity || 0);
  const received = parseFloat(poLine.received_qty || 0);
  let created = parseFloat(poLine.created_received_qty || 0);
  if (pageStatus === "Edit") created = Math.max(0, roundQty(created - (oldAgg.get(lid) || 0)));

  const maxReceivable = roundQty((ordered - received) * (100 + tol) / 100);
  if (newQty > maxReceivable) {
    hardErrors.push(`${name}: receiving ${newQty} exceeds remaining receivable ${Math.max(0, maxReceivable)} (Ordered ${ordered}, Already received ${received}).`);
  }

  const maxAllowed = roundQty(ordered * (100 + tol) / 100);
  const totalAfter = roundQty(received + created + newQty);
  if (totalAfter > maxAllowed) {
    warnings.push(`${name}: committed total ${totalAfter} would exceed PO max ${maxAllowed} (Received ${received}, In Created GRs ${created}, This GR ${newQty}).`);
  }
}

const hasError = hardErrors.length > 0 ? 1 : 0;
const errorMessage = hasError ? ("Cannot save - quantity exceeds purchase order:\n" + hardErrors.join("\n")) : null;
const hasWarning = warnings.length > 0 ? 1 : 0;
const warningMessage = hasWarning ? ("Over-Commitment Warning:\n" + warnings.join("\n") + "\n\nThis GR can be saved as Created, but may fail to receive if other Created GRs are received first.\nDo you want to proceed?") : null;

return { hasError, errorMessage, hasWarning, warningMessage };

const roundQty = (v) => parseFloat(parseFloat(v || 0).toFixed(3));
const tableGR = {{node:cn_fill.data.allData.table_gr}} || [];
const poDataList = {{node:search_po.data.data}} || [];
const pageStatus = {{workflowparams:pageStatus}};
const origRaw = {{node:search_origGR.data.data}} || [];
const originalGR = Array.isArray(origRaw) ? (origRaw[0] || null) : origRaw;
const originalTableGR = (originalGR && originalGR.table_gr) ? originalGR.table_gr : [];

const isParent = (r) => r.is_split === "Yes" && r.parent_or_child === "Parent";
const aggregate = (rows) => {
  const m = new Map();
  for (const gr of rows) {
    if (isParent(gr)) continue;
    const lid = gr.po_line_item_id;
    if (!lid) continue;
    m.set(lid, roundQty((m.get(lid) || 0) + parseFloat(gr.received_qty || 0)));
  }
  return m;
};

const newAgg = aggregate(tableGR);
const oldAgg = pageStatus === "Edit" ? aggregate(originalTableGR) : new Map();

const poDataUpdates = [];
for (const po of poDataList) {
  const lines = po.table_po || [];
  const updatedLines = lines.map((line) => {
    const applyQty = roundQty((newAgg.get(line.id) || 0) - (oldAgg.get(line.id) || 0));
    if (applyQty === 0) return line;
    const current = parseFloat(line.created_received_qty || 0);
    return { ...line, created_received_qty: Math.max(0, roundQty(current + applyQty)) };
  });
  poDataUpdates.push({ id: po.id, table_po: updatedLines, gr_status: "Created" });
}

return { poDataUpdates, hasUpdates: poDataUpdates.length > 0 ? 1 : 0 };
